args.sparql:
SELECT ?company ?companyLabel ?revenue WHERE {
  ?company wdt:P31/wdt:P279* wd:Q43229 .
  ?company p:P2139 ?statement .
  ?statement ps:P2139 ?value ;
             pq:P6011 wd:Q4917 ;
             pq:P585 ?date .
  FILTER(YEAR(?date) >= 2022)
  FILTER(isNumeric(?value))
  BIND(xsd:decimal(?value) AS ?revenue)
  FILTER(?revenue < 1000000000000)
  OPTIONAL { ?company rdfs:label ?companyLabel . FILTER(LANG(?companyLabel) = "en") }
}
ORDER BY DESC(?revenue)
LIMIT 1
